const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema, GraphQLID, GraphQLString, GraphQLList, GraphQLNonNull } = require('graphql');
const { Pool } = require('pg');

// PostgreSQL connection pool
const pool = new Pool({
  user: 'your_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

// Define GraphQL schema
const schema = buildSchema(`
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    authorId: ID!
    author: Author
  }

  type Query {
    posts: [Post]
    post(id: ID!): Post
  }
`);

// Define resolvers
const root = {
  posts: async () => {
    const { rows } = await pool.query('SELECT * FROM posts');
    return rows.map(async (post) => ({
      ...post,
      author: await getAuthor(post.authorId),
    }));
  },
  post: async ({ id }) => {
    const { rows } = await pool.query('SELECT * FROM posts WHERE id = $1', [id]);
    if (!rows.length) return null;
    const post = rows[0];
    post.author = await getAuthor(post.authorId);
    return post;
  },
};

// Helper function to fetch author by ID
const getAuthor = async (authorId) => {
  const { rows } = await pool.query('SELECT * FROM authors WHERE id = $1', [authorId]);
  if (!rows.length) return null;
  return rows[0];
};

// Create Express app and GraphQL endpoint
const app = express();
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: true,
}));

// Start server
app.listen(4000, () => {
  console.log('Running a GraphQL API server at http://localhost:4000/graphql');
});